package hellfirepvp.astralsorcery.datagen.data.recipes.altar;

import hellfirepvp.astralsorcery.common.crafting.recipe.altar.builtin.ConstellationCopyStatsRecipe;
import net.minecraft.world.level.item.ItemStack;
import net.minecraft.world.level.item.Items;
import hellfirepvp.astralsorcery.common.util.NameUtil;
import net.minecraftforge.common.Tags;
import hellfirepvp.astralsorcery.common.lib.TagsAS;
import net.minecraft.world.level.level.material.Fluid;
import hellfirepvp.astralsorcery.common.lib.FluidsAS;
import net.minecraft.world.level.item.Item;
import net.minecraft.tags.TagKey;
import net.minecraft.tags.ItemTags;
import hellfirepvp.astralsorcery.common.lib.AltarRecipeEffectsAS;
import net.minecraft.world.level.level.ItemLike;
import hellfirepvp.astralsorcery.common.lib.ItemsAS;
import net.minecraft.world.level.item.crafting.Ingredient;
import hellfirepvp.astralsorcery.common.crafting.helper.ingredient.CrystalIngredient;
import hellfirepvp.astralsorcery.common.crafting.recipe.altar.AltarRecipeGrid;
import net.minecraftforge.registries.ForgeRegistryEntry;
import hellfirepvp.astralsorcery.common.block.tile.altar.AltarType;
import hellfirepvp.astralsorcery.common.lib.BlocksAS;
import hellfirepvp.astralsorcery.common.crafting.builder.SimpleAltarRecipeBuilder;
import hellfirepvp.astralsorcery.common.crafting.recipe.altar.AltarRecipeTypeHandler;
import net.minecraft.data.IFinishedRecipe;
import java.util.function.Consumer;

public class CelestialAltarRecipeProvider
{
    public static void registerAltarRecipes(final Consumer<IFinishedRecipe> registrar) {
        registerRecipes(registrar);
        registerColoredLensRecipes(registrar);
    }
    
    private static void registerRecipes(final Consumer<IFinishedRecipe> registrar) {
        SimpleAltarRecipeBuilder.ofType(AltarRecipeTypeHandler.ALTAR_UPGRADE_TRAIT).createRecipe((ForgeRegistryEntry<?>)BlocksAS.ALTAR_RADIANCE, AltarType.CONSTELLATION).setStarlightRequirement(0.8f).setInputs(AltarRecipeGrid.builder().patternLine("RM MR").patternLine("ARLRA").patternLine("  C  ").patternLine("AR RA").patternLine("RM MR").key('C', new CrystalIngredient(false, true)).key('L', (ItemLike)ItemsAS.GLASS_LENS).key('A', (ItemLike)ItemsAS.RESONATING_GEM).key('M', (ItemLike)BlocksAS.BLACK_MARBLE_RAW).key('R', (ItemLike)BlocksAS.MARBLE_RUNED)).addOutput((ItemLike)BlocksAS.ALTAR_RADIANCE).addAltarEffect(AltarRecipeEffectsAS.PILLAR_SPARKLE).addAltarEffect(AltarRecipeEffectsAS.LUMINESCENCE_FLARE).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)BlocksAS.TREE_BEACON, AltarType.CONSTELLATION).setStarlightRequirement(0.6f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine(" LRL ").patternLine(" LSL ").patternLine(" LFL ").patternLine("MM MM").key('R', (ItemLike)ItemsAS.RESONATING_GEM).key('L', (ITag.INamedTag<Item>)ItemTags.field_206963_E).key('S', (ITag.INamedTag<Item>)ItemTags.field_200037_g).key('F', (Fluid)FluidsAS.LIQUID_STARLIGHT_SOURCE).key('M', (ItemLike)BlocksAS.MARBLE_RUNED)).addOutput((ItemLike)BlocksAS.TREE_BEACON).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)BlocksAS.REFRACTION_TABLE, AltarType.CONSTELLATION).setStarlightRequirement(0.7f).setInputs(AltarRecipeGrid.builder().patternLine("D   D").patternLine("PR RP").patternLine(" S S ").patternLine("PBBBP").patternLine("M   M").key('S', TagsAS.Items.INGOTS_STARMETAL).key('R', (ItemLike)ItemsAS.RESONATING_GEM).key('M', (ItemLike)BlocksAS.MARBLE_RUNED).key('B', (ItemLike)BlocksAS.BLACK_MARBLE_RUNED).key('D', (ITag.INamedTag<Item>)Tags.Items.DYES).key('P', (ItemLike)BlocksAS.INFUSED_WOOD_COLUMN)).addOutput((ItemLike)BlocksAS.REFRACTION_TABLE).addAltarEffect(AltarRecipeEffectsAS.ALTAR_RANDOM_SPARKLE).addAltarEffect(AltarRecipeEffectsAS.ALTAR_DEFAULT_LIGHTBEAM).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)ItemsAS.INFUSED_GLASS, AltarType.CONSTELLATION).setStarlightRequirement(0.6f).setInputs(AltarRecipeGrid.builder().patternLine("S   S").patternLine("S   S").patternLine(" GLG ").patternLine("S   S").patternLine("S   S").key('L', TagsAS.Items.COLORED_LENS).key('G', (ItemLike)ItemsAS.GLASS_LENS).key('S', TagsAS.Items.DUSTS_STARDUST)).addOutput((ItemLike)ItemsAS.INFUSED_GLASS).build(registrar);
        SimpleAltarRecipeBuilder.ofType(AltarRecipeTypeHandler.CONSTELLATION_CRYSTAL_AVERAGE).createRecipe((ForgeRegistryEntry<?>)BlocksAS.PRISM, AltarType.CONSTELLATION).setStarlightRequirement(0.4f).setInputs(AltarRecipeGrid.builder().patternLine(" A A ").patternLine("GPSPG").patternLine(" LCL ").patternLine("EPSPE").patternLine("RR RR").key('C', new CrystalIngredient(false, false)).key('S', TagsAS.Items.DUSTS_STARDUST).key('A', (ItemLike)ItemsAS.RESONATING_GEM).key('L', (ItemLike)ItemsAS.GLASS_LENS).key('P', (ITag.INamedTag<Item>)Tags.Items.GLASS_PANES).key('G', (ITag.INamedTag<Item>)Tags.Items.INGOTS_GOLD).key('R', (ItemLike)BlocksAS.MARBLE_RUNED).key('E', (ItemLike)BlocksAS.INFUSED_WOOD_ENGRAVED)).addOutput((ItemLike)BlocksAS.PRISM).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe(NameUtil.suffixPath(ItemsAS.ENCHANTMENT_AMULET.getRegistryName(), "_init"), AltarType.CONSTELLATION).setStarlightRequirement(0.7f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine(" GTG ").patternLine(" SZS ").patternLine("S E S").patternLine(" S S ").key('G', (ITag.INamedTag<Item>)Tags.Items.INGOTS_GOLD).key('T', (ITag.INamedTag<Item>)Tags.Items.STRING).key('E', (ItemLike)Items.field_151061_bv).key('Z', (ItemLike)ItemsAS.SHIFTING_STAR).key('S', TagsAS.Items.DUSTS_STARDUST)).addOutput((ItemLike)ItemsAS.ENCHANTMENT_AMULET).addAltarEffect(AltarRecipeEffectsAS.LARGE_DUST_SWIRL).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe(NameUtil.suffixPath(ItemsAS.ENCHANTMENT_AMULET.getRegistryName(), "_reroll"), AltarType.CONSTELLATION).setStarlightRequirement(0.7f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine("  R  ").patternLine("  A  ").patternLine("SSLSS").patternLine("     ").key('L', (Fluid)FluidsAS.LIQUID_STARLIGHT_SOURCE).key('A', (ItemLike)ItemsAS.ENCHANTMENT_AMULET).key('R', (ItemLike)ItemsAS.RESONATING_GEM).key('S', TagsAS.Items.DUSTS_STARDUST)).addOutput((ItemLike)ItemsAS.ENCHANTMENT_AMULET).addAltarEffect(AltarRecipeEffectsAS.LARGE_DUST_SWIRL).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)BlocksAS.RITUAL_LINK, AltarType.CONSTELLATION).setStarlightRequirement(0.4f).setInputs(AltarRecipeGrid.builder().patternLine(" N N ").patternLine(" NGN ").patternLine(" LAL ").patternLine(" PSP ").patternLine(" P P ").key('L', (ItemLike)ItemsAS.GLASS_LENS).key('P', (ITag.INamedTag<Item>)Tags.Items.GLASS_PANES).key('G', (ITag.INamedTag<Item>)Tags.Items.INGOTS_GOLD).key('N', (ITag.INamedTag<Item>)Tags.Items.NUGGETS_GOLD).key('S', TagsAS.Items.DUSTS_STARDUST).key('A', (ItemLike)ItemsAS.RESONATING_GEM)).addOutput(new ItemStack((ItemLike)BlocksAS.RITUAL_LINK, 2)).build(registrar);
        SimpleAltarRecipeBuilder.ofType(AltarRecipeTypeHandler.CONSTELLATION_COPY_CRYSTAL).createRecipe((ForgeRegistryEntry<?>)BlocksAS.ROCK_COLLECTOR_CRYSTAL, AltarType.CONSTELLATION).modify(recipe -> recipe.setConstellationSlot(12)).setStarlightRequirement(0.65f).setInputs(AltarRecipeGrid.builder().patternLine("SI IS").patternLine("R   R").patternLine("  C  ").patternLine("R   R").patternLine("SI IS").key('C', new CrystalIngredient(true, false, false, false)).key('R', (ItemLike)ItemsAS.RESONATING_GEM).key('S', TagsAS.Items.DUSTS_STARDUST).key('I', (ItemLike)ItemsAS.ILLUMINATION_POWDER)).addOutput((ItemLike)BlocksAS.ROCK_COLLECTOR_CRYSTAL).build(registrar);
        SimpleAltarRecipeBuilder.ofType(AltarRecipeTypeHandler.CONSTELLATION_COPY_CRYSTAL).createRecipe((ForgeRegistryEntry<?>)BlocksAS.CELESTIAL_COLLECTOR_CRYSTAL, AltarType.CONSTELLATION).modify(recipe -> recipe.setConstellationSlot(12)).setStarlightRequirement(0.65f).setInputs(AltarRecipeGrid.builder().patternLine("SI IS").patternLine("R   R").patternLine("  C  ").patternLine("R   R").patternLine("SI IS").key('C', new CrystalIngredient(true, true, false, true)).key('R', (ItemLike)ItemsAS.RESONATING_GEM).key('S', TagsAS.Items.DUSTS_STARDUST).key('I', (ItemLike)ItemsAS.ILLUMINATION_POWDER)).addOutput((ItemLike)BlocksAS.CELESTIAL_COLLECTOR_CRYSTAL).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)ItemsAS.ILLUMINATION_WAND, AltarType.CONSTELLATION).setStarlightRequirement(0.7f).setInputs(AltarRecipeGrid.builder().patternLine("   I ").patternLine("  ISI").patternLine("  RI ").patternLine(" R   ").patternLine("R    ").key('R', (ItemLike)BlocksAS.MARBLE_RUNED).key('I', (ItemLike)ItemsAS.ILLUMINATION_POWDER).key('S', (ItemLike)ItemsAS.SHIFTING_STAR)).addOutput((ItemLike)ItemsAS.ILLUMINATION_WAND).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)BlocksAS.INFUSER, AltarType.CONSTELLATION).setStarlightRequirement(0.3f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine("PASAP").patternLine(" GLG ").patternLine("PRRRP").patternLine("PG GP").key('P', (ItemLike)BlocksAS.MARBLE_PILLAR).key('R', (ItemLike)BlocksAS.MARBLE_RUNED).key('A', (ItemLike)ItemsAS.AQUAMARINE).key('G', (ITag.INamedTag<Item>)Tags.Items.INGOTS_GOLD).key('L', (Fluid)FluidsAS.LIQUID_STARLIGHT_SOURCE).key('S', TagsAS.Items.INGOTS_STARMETAL)).addOutput((ItemLike)BlocksAS.INFUSER).build(registrar);
    }
    
    private static void registerColoredLensRecipes(final Consumer<IFinishedRecipe> registrar) {
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)ItemsAS.COLORED_LENS_SPECTRAL, AltarType.CONSTELLATION).setStarlightRequirement(0.5f).setInputs(AltarRecipeGrid.builder().patternLine("S   S").patternLine("  R  ").patternLine(" ILI ").patternLine("  R  ").patternLine("S   S").key('L', (ItemLike)ItemsAS.GLASS_LENS).key('I', (ItemLike)ItemsAS.ILLUMINATION_POWDER).key('R', (ItemLike)ItemsAS.RESONATING_GEM).key('S', TagsAS.Items.DUSTS_STARDUST)).addOutput((ItemLike)ItemsAS.COLORED_LENS_SPECTRAL).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)ItemsAS.COLORED_LENS_FIRE, AltarType.CONSTELLATION).setStarlightRequirement(0.5f).setInputs(AltarRecipeGrid.builder().patternLine("B   B").patternLine("B A B").patternLine("  L  ").patternLine("B A B").patternLine("B   B").key('L', (ItemLike)ItemsAS.GLASS_LENS).key('B', (ItemLike)Items.field_151065_br).key('A', (ItemLike)ItemsAS.AQUAMARINE)).addOutput((ItemLike)ItemsAS.COLORED_LENS_FIRE).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)ItemsAS.COLORED_LENS_BREAK, AltarType.CONSTELLATION).setStarlightRequirement(0.5f).setInputs(AltarRecipeGrid.builder().patternLine("A   A").patternLine("  D  ").patternLine("  L  ").patternLine("G P G").patternLine("     ").key('L', (ItemLike)ItemsAS.GLASS_LENS).key('A', (ItemLike)ItemsAS.AQUAMARINE).key('G', (ITag.INamedTag<Item>)Tags.Items.INGOTS_GOLD).key('P', (ItemLike)Items.field_151035_b).key('D', (ITag.INamedTag<Item>)Tags.Items.GEMS_DIAMOND)).addOutput((ItemLike)ItemsAS.COLORED_LENS_BREAK).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)ItemsAS.COLORED_LENS_DAMAGE, AltarType.CONSTELLATION).setStarlightRequirement(0.5f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine("I D I").patternLine(" ILI ").patternLine(" F F ").patternLine("A   A").key('L', (ItemLike)ItemsAS.GLASS_LENS).key('A', (ItemLike)ItemsAS.AQUAMARINE).key('I', (ITag.INamedTag<Item>)Tags.Items.INGOTS_IRON).key('D', (ITag.INamedTag<Item>)Tags.Items.GEMS_DIAMOND).key('F', (ItemLike)Items.field_151145_ak)).addOutput((ItemLike)ItemsAS.COLORED_LENS_DAMAGE).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)ItemsAS.COLORED_LENS_GROWTH, AltarType.CONSTELLATION).setStarlightRequirement(0.5f).setInputs(AltarRecipeGrid.builder().patternLine("AK KA").patternLine("  A  ").patternLine(" CLC ").patternLine("     ").patternLine("AS SA").key('L', (ItemLike)ItemsAS.GLASS_LENS).key('A', (ItemLike)ItemsAS.AQUAMARINE).key('C', (ITag.INamedTag<Item>)Tags.Items.CROPS_CARROT).key('K', (ItemLike)Items.field_222065_kN).key('S', (ITag.INamedTag<Item>)Tags.Items.SEEDS)).addOutput((ItemLike)ItemsAS.COLORED_LENS_GROWTH).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)ItemsAS.COLORED_LENS_PUSH, AltarType.CONSTELLATION).setStarlightRequirement(0.5f).setInputs(AltarRecipeGrid.builder().patternLine("G   G").patternLine("AF FA").patternLine("  L  ").patternLine("     ").patternLine("G   G").key('L', (ItemLike)ItemsAS.GLASS_LENS).key('A', (ItemLike)ItemsAS.AQUAMARINE).key('F', (ITag.INamedTag<Item>)Tags.Items.FEATHERS).key('G', (ITag.INamedTag<Item>)Tags.Items.DUSTS_GLOWSTONE)).addOutput((ItemLike)ItemsAS.COLORED_LENS_PUSH).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)ItemsAS.COLORED_LENS_REGENERATION, AltarType.CONSTELLATION).setStarlightRequirement(0.5f).setInputs(AltarRecipeGrid.builder().patternLine("A   A").patternLine("  T  ").patternLine("  L  ").patternLine("S D S").patternLine("     ").key('L', (ItemLike)ItemsAS.GLASS_LENS).key('A', (ItemLike)ItemsAS.AQUAMARINE).key('D', (ITag.INamedTag<Item>)Tags.Items.GEMS_DIAMOND).key('S', TagsAS.Items.DUSTS_STARDUST).key('T', (ItemLike)Items.field_151073_bk)).addOutput((ItemLike)ItemsAS.COLORED_LENS_REGENERATION).build(registrar);
    }
}
